from flask import Flask, request, make_response

app = Flask(__name__)

@app.route('/greetUser')
def greet():
    '''
    Grab the "username" from the request, give it a quick check,
    then whip up a friendly welcome message and send it back.
    Great for making visitors feel right at home on your site!
    '''
    username = request.args.get('username', '').strip()
    if not username:
        return make_response('Hey there! What should we call you?', 400)
    return make_response(f'Welcome, {username}! Glad you stopped by!', 200)

