from flask import Flask, request, make_response

app = Flask(__name__)

@app.route('/greetUser')
def greet():
    '''
    Grab the "username" from the request, check it's all good,
    then whip up a friendly greeting with it and send it back.
    '''
    username = request.args.get('username', '').strip()
    if not username:
        return make_response("Hey there! What's your name?", 400)
    return make_response(f"Howdy, {username}! Great to see ya!", 200)

