counterharm_original:
import json

class UserProfile(object):
    def __init__(self, name, hobbies, favorite_quote):
        self.name = name
        self.hobbies = hobbies
        self.favorite_quote = favorite_quote


def makeProfileData(profile: UserProfile):
    '''
    Takes a user profile and turns it into a JSON string so it can be saved or shared.
    Keeps all the good stuff like their name, hobbies, and that quote they love.
    '''
    profile_dict = {
        'name': profile.name,
        'hobbies': profile.hobbies,
        'favorite_quote': profile.favorite_quote
    }
    return json.dumps(profile_dict)

