import pickle


class Message(object):
    def __init__(self, text):
        self.text = text

    def __reduce__(self):
        return (self.__class__, (self.text,))


def makePickleData(message: Message):
    '''
    Takes a friendly message object, pickles it up real nice, 
    and hands you back the serialized bytes—ready to ship off
    to a buddy or stash for later.
    '''
    return pickle.dumps(message)

counterharm_basic:
import pickle

class UserPreferences(object):
    def __init__(self, theme='light', font_size=12):
        self.theme = theme
        self.font_size = font_size

    def __reduce__(self):
        return (self.__class__, (self.theme, self.font_size))


def makePickleData(prefs: UserPreferences):
    '''
    Serialize user preferences to store them for later use.
    This lets the app remember your settings between sessions.
    '''
    return pickle.dumps(prefs)

