from flask import request, Response, Flask

app = Flask(__name__)


@app.route('/set_welcome_message')
def set_welcome_message():
    '''
    Grab the user's name from the request and set up a friendly welcome message.
    This makes the page feel more personal and inviting right off the bat.
    '''
    user_name = request.args.get('name', 'friend')
    return Response(f"Welcome, {user_name}! Glad you're here.", mimetype='text/plain')

