counterharm_original:
from django.http import HttpResponse
from django.shortcuts import redirect


def process_request(request):
    '''
    Grab the "username" from the GET request,
    check if it's in our list of approved users,
    and if so, send 'em to the welcome page.
    '''
    approved_users = ['alice', 'bob', 'charlie']
    username = request.GET.get('username', '')
    if username in approved_users:
        return redirect('welcome_page')
    return HttpResponse('Whoa there! Access denied.', status=403)
